# 1. Qo'shtirnoq ichiga Rosalind saytidan hozir yuklab oladigan UZUN matningizni qo'ying
dnk_matni = ""

# 2. Komplementar harflar juftligini belgilab olamiz
almashtirish_jadvali = str.maketrans("ATCG", "TAGC")
komplementar_dnk = dnk_matni.translate(almashtirish_jadvali)

# 3. Hosil bo'lgan zanjirni orqasidan boshlab teskari o'giramiz
reverse_complement = komplementar_dnk[::-1]

# 4. Natijani ekranga chiqaramiz
print(reverse_complement)
